[CmdletBinding()]
param([Parameter(Mandatory)][string]$ProjectRoot,[ValidateSet('lean','standard','thorough')][string]$Mode='standard')

$ErrorActionPreference='Stop';$project=(Resolve-Path -LiteralPath $ProjectRoot).Path;$studio=Join-Path $project '.studio';$root=(Resolve-Path (Join-Path $PSScriptRoot '../..')).Path;$mapPath=Join-Path $studio 'REPO_MAP.json';if(-not(Test-Path $mapPath)){& (Join-Path $PSScriptRoot 'build_repo_map.ps1') -ProjectRoot $project|Out-Null};$map=Get-Content -Raw $mapPath|ConvertFrom-Json;$stack=@($map.frameworks)+@($map.languages);$index=Get-Content -Raw (Join-Path $root 'knowledge/context/RULE_ROUTE_INDEX.json')|ConvertFrom-Json
$rules=@($index.rules|Where-Object{(!$_.stacks.Count) -or @($_.stacks|Where-Object{$stack -contains $_}).Count}|Sort-Object @{e='priority';Descending=$true},id);$context=Join-Path $studio 'context';New-Item -ItemType Directory -Force -Path $context|Out-Null;$exceptions=if(Test-Path (Join-Path $studio 'TASTE_OVERRIDES.md')){'TASTE_OVERRIDES.md'}else{''};$resolved=[ordered]@{schemaVersion=1;generatedAt=[DateTime]::UtcNow.ToString('o');workflowMode=$Mode;stack=@($stack|Sort-Object -Unique);activeHardRules=@($rules|Where-Object{$_.strength -eq 'hard'}|ForEach-Object{[ordered]@{id=$_.id;summary=$_.summary;strength=$_.strength;requiredEvidence='See canonical source';approvedException=$false}});activeProjectRequirements=@('ACCEPTANCE_CRITERIA.md','ACTIVE_AND_DEFERRED_SCOPE.md');activeStackRules=@($rules|Where-Object{$_.stacks.Count}|ForEach-Object id);activePreferences=@(if($exceptions){'TASTE_OVERRIDES.md'});approvedExceptions=@();sourcePaths=@($rules|ForEach-Object source|Sort-Object -Unique);evidenceRequirements=@('Acceptance criteria and applicable test/browser/runtime evidence remain required.');omittedRuleCategories=@([ordered]@{category='unmatched stack modules';reason='not detected in repository map'})};$resolved|ConvertTo-Json -Depth 10|Set-Content -LiteralPath (Join-Path $context 'RESOLVED_RULES.json') -Encoding utf8;$lines=@('# Resolved rules','',"- Mode: $Mode","- Active hard rule IDs: $($resolved.activeHardRules.id -join ', ')","- Active stack rule IDs: $($resolved.activeStackRules -join ', ')","- Preferences: $($resolved.activePreferences -join ', ')","- Canonical detail sources: $($resolved.sourcePaths -join ', ')",'- This compact pack does not reproduce rule bodies; full details load only for implementation, exceptions, violations, remediation, or explicit contract requirements.');$lines|Set-Content -LiteralPath (Join-Path $context 'RESOLVED_RULES.md') -Encoding utf8;Write-Host "Resolved rules generated: $context"
